from flask import Flask, redirect, url_for, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'
OPENID_CONNECT_ISSUER = 'https://your-openid-issuer.com'
CLIENT_ID = 'your-client-id'

@app.route('/login')
def login():
    authorization_url = f"{OPENID_CONNECT_ISSUER}/authorize?response_type=id_token&client_id={CLIENT_ID}&redirect_uri={url_for('callback', _external=True)}&scope=openid"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    token_response = requests.post(
        f"{OPENID_CONNECT_ISSUER}/token",
        data={
            'grant_type': 'authorization_code',
            'code': session.get('authz_code'),
            'redirect_uri': url_for('callback', _external=True),
            'client_id': CLIENT_ID,
            'client_secret': 'your-client-secret'
        }
    )
    token_data = token_response.json()
    id_token = token_data['id_token']
    # Process the ID token as needed
    return f"Logged in with ID Token: {id_token}"

if __name__ == '__main__':
    app.run(debug=True)